import { takaro, data } from '@takaro/helpers';

const STATUS_KEY = 'dc_last_status';
const CONFIG_HASH_KEY = 'dc_config_hash';
const LAST_PROCESSED_KEY = 'dc_last_processed';

const MONTH_NAMES = {
  jan: 1,
  feb: 2,
  mar: 3,
  apr: 4,
  may: 5,
  jun: 6,
  jul: 7,
  aug: 8,
  sep: 9,
  oct: 10,
  nov: 11,
  dec: 12,
};

const DOW_NAMES = {
  sun: 0,
  mon: 1,
  tue: 2,
  wed: 3,
  thu: 4,
  fri: 5,
  sat: 6,
};

function computeHash(value) {
  const text = JSON.stringify(value);
  let hash = 0;
  for (let i = 0; i < text.length; i++) {
    hash = ((hash << 5) - hash) + text.charCodeAt(i);
    hash |= 0;
  }
  return String(hash);
}

function normalizeCronjobs(userConfig) {
  if (!userConfig || typeof userConfig !== 'object') return [];
  if (userConfig.cronjobs == null) return [];
  if (!Array.isArray(userConfig.cronjobs)) {
    throw new Error('cronjobs must be an array');
  }
  return userConfig.cronjobs;
}

function parseFieldValue(raw, names) {
  const text = String(raw).toLowerCase();
  if (names && Object.prototype.hasOwnProperty.call(names, text)) {
    return names[text];
  }
  if (!/^\d+$/.test(text)) return null;
  return Number(text);
}

function validateCronField(field, min, max, options = {}) {
  const parts = field.split(',');
  if (parts.some((part) => part === '')) return false;

  for (const part of parts) {
    const [base, stepText] = part.split('/');
    if (part.split('/').length > 2) return false;

    if (stepText !== undefined) {
      if (!/^\d+$/.test(stepText)) return false;
      if (Number(stepText) < 1) return false;
    }

    if (base === '*') continue;
    if (base === '?' && options.allowQuestion) continue;

    const range = base.split('-');
    if (range.length > 2 || range.some((value) => value === '')) return false;

    const start = parseFieldValue(range[0], options.names);
    if (start == null || start < min || start > max) return false;

    if (range.length === 2) {
      const end = parseFieldValue(range[1], options.names);
      if (end == null || end < min || end > max) return false;
      if (start > end) return false;
    }
  }

  return true;
}

function isValidCronSyntax(cronExpression) {
  if (typeof cronExpression !== 'string') return false;
  const expression = cronExpression.trim();
  if (expression === '') return false;
  if (/^@(yearly|annually|monthly|weekly|daily|hourly|reboot)$/.test(expression)) return true;

  const parts = expression.split(/\s+/);
  if (parts.length !== 5) return false;

  return (
    validateCronField(parts[0], 0, 59) &&
    validateCronField(parts[1], 0, 23) &&
    validateCronField(parts[2], 1, 31, { allowQuestion: true }) &&
    validateCronField(parts[3], 1, 12, { names: MONTH_NAMES }) &&
    validateCronField(parts[4], 0, 7, { allowQuestion: true, names: DOW_NAMES })
  );
}

function sanitizeName(name) {
  if (typeof name !== 'string') return '';
  return name
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 48);
}

function validateAndBuildDesiredJobs(rawCronjobs, gameServerId) {
  const errors = [];
  const desiredJobs = [];
  const serverShortId = gameServerId.substring(0, 8);
  const serverPrefix = `cr-${serverShortId}-`;
  let jobCounter = 1;

  for (let i = 0; i < rawCronjobs.length; i++) {
    const rowNumber = i + 1;
    const job = rawCronjobs[i];

    if (!job || typeof job !== 'object' || Array.isArray(job)) {
      errors.push(`row ${rowNumber}: cronjob must be an object`);
      continue;
    }

    const temporalValue = typeof job.temporalValue === 'string' ? job.temporalValue.trim() : '';
    if (!isValidCronSyntax(temporalValue)) {
      errors.push(`row ${rowNumber}: invalid temporalValue "${String(job.temporalValue ?? '')}"`);
    }

    if (job.name != null && (typeof job.name !== 'string' || job.name.trim() === '')) {
      errors.push(`row ${rowNumber}: name must be a non-empty string when provided`);
    }

    if (typeof job.command !== 'string' || job.command.trim() === '') {
      errors.push(`row ${rowNumber}: command must be a non-empty string`);
      continue;
    }

    const commands = job.command.split(';').map((command) => command.trim()).filter(Boolean);
    if (commands.length === 0) {
      errors.push(`row ${rowNumber}: command sequence is empty`);
      continue;
    }

    if (!isValidCronSyntax(temporalValue)) continue;

    const sanitizedName = sanitizeName(job.name);
    for (let cmdIndex = 0; cmdIndex < commands.length; cmdIndex++) {
      const seqSuffix = commands.length > 1 ? `-seq${cmdIndex + 1}` : '';
      const nameSuffix = sanitizedName ? `-${sanitizedName}${seqSuffix}` : seqSuffix;
      const name = `${serverPrefix}${jobCounter}${nameSuffix}`;
      jobCounter++;

      desiredJobs.push({
        name,
        temporalValue,
        command: commands[cmdIndex],
        function: buildGeneratedFunction(gameServerId, commands[cmdIndex]),
      });
    }
  }

  return { errors, desiredJobs, serverPrefix };
}

function buildGeneratedFunction(gameServerId, command) {
  return `import { takaro, data } from '@takaro/helpers';

async function main() {
  if (data.gameServerId !== ${JSON.stringify(gameServerId)}) return;
  await takaro.gameserver.gameServerControllerExecuteCommand(data.gameServerId, {
    command: ${JSON.stringify(command)},
  });
}

await main();`;
}

async function listCronjobs(versionId) {
  const all = [];
  const limit = 100;
  let page = 0;

  while (true) {
    const res = await takaro.cronjob.cronJobControllerSearch({
      filters: { versionId: [versionId] },
      limit,
      page,
    });
    const rows = res.data.data;
    all.push(...rows);
    if (rows.length < limit) break;
    page++;
    if (page > 100) throw new Error('cronjob pagination exceeded safety limit');
  }

  return all;
}

async function findVariable(gameServerId, moduleId, key) {
  const res = await takaro.variable.variableControllerSearch({
    filters: {
      key: [key],
      moduleId: [moduleId],
      gameServerId: [gameServerId],
    },
  });
  return res.data.data[0] ?? null;
}

async function writeVariable(gameServerId, moduleId, key, value) {
  const serialized = typeof value === 'string' ? value : JSON.stringify(value);
  const existing = await findVariable(gameServerId, moduleId, key);
  if (existing) {
    await takaro.variable.variableControllerUpdate(existing.id, { value: serialized });
    return;
  }

  try {
    await takaro.variable.variableControllerCreate({
      key,
      value: serialized,
      gameServerId,
      moduleId,
    });
  } catch (error) {
    if (error?.response?.status !== 409) throw error;
    const created = await findVariable(gameServerId, moduleId, key);
    if (!created) throw error;
    await takaro.variable.variableControllerUpdate(created.id, { value: serialized });
  }
}

async function writeStatus(gameServerId, moduleId, status) {
  await writeVariable(gameServerId, moduleId, STATUS_KEY, {
    ...status,
    timestamp: new Date().toISOString(),
  });
}

async function reconcileCronjobs(versionId, existingCronjobs, desiredJobs, serverPrefix) {
  const desiredByName = new Map(desiredJobs.map((job) => [job.name, job]));
  let created = 0;
  let updated = 0;
  let removed = 0;

  for (const desired of desiredJobs) {
    const existing = existingCronjobs.find((job) => job.name === desired.name);
    if (!existing) {
      try {
        await takaro.cronjob.cronJobControllerCreate({
          name: desired.name,
          temporalValue: desired.temporalValue,
          versionId,
          function: desired.function,
        });
        created++;
      } catch (error) {
        if (error?.response?.status !== 409) throw error;
        const conflict = (await takaro.cronjob.cronJobControllerSearch({
          filters: {
            name: [desired.name],
            versionId: [versionId],
          },
        })).data.data[0];
        if (!conflict) throw error;
        await takaro.cronjob.cronJobControllerUpdate(conflict.id, {
          name: desired.name,
          temporalValue: desired.temporalValue,
          function: desired.function,
        });
        updated++;
      }
      continue;
    }

    const existingFunctionCode = typeof existing.function === 'string' ? existing.function : existing.function?.code;
    if (existing.temporalValue !== desired.temporalValue || existingFunctionCode !== desired.function) {
      await takaro.cronjob.cronJobControllerUpdate(existing.id, {
        name: desired.name,
        temporalValue: desired.temporalValue,
        function: desired.function,
      });
      updated++;
    }
  }

  for (const existing of existingCronjobs) {
    if (
      existing.name !== 'cronJobGenerator' &&
      existing.name.startsWith(serverPrefix) &&
      !desiredByName.has(existing.name)
    ) {
      await takaro.cronjob.cronJobControllerRemove(existing.id);
      removed++;
    }
  }

  return { created, updated, removed };
}

async function main() {
  const { gameServerId, module: mod } = data;
  const moduleId = mod.moduleId;
  const versionId = mod.versionId;
  const serverShortId = gameServerId.substring(0, 8);

  console.log(`dynamic-cronjobs: generator starting for server ${serverShortId}`);

  let rawCronjobs;
  try {
    rawCronjobs = normalizeCronjobs(mod.userConfig);
  } catch (error) {
    const message = `dynamic-cronjobs: validation failed: ${error.message}`;
    console.log(message);
    await writeStatus(gameServerId, moduleId, {
      ok: false,
      errors: [error.message],
      desiredCount: 0,
    });
    throw new Error(message);
  }

  const { errors, desiredJobs, serverPrefix } = validateAndBuildDesiredJobs(rawCronjobs, gameServerId);
  const currentConfigHash = computeHash(rawCronjobs);

  if (errors.length > 0) {
    console.log(`dynamic-cronjobs: validation failed; no cronjobs changed. ${errors.join(' | ')}`);
    await writeStatus(gameServerId, moduleId, {
      ok: false,
      errors,
      desiredCount: desiredJobs.length,
      configHash: currentConfigHash,
    });
    throw new Error(`dynamic-cronjobs: validation failed: ${errors.join('; ')}`);
  }

  const existingCronjobs = await listCronjobs(versionId);
  const result = await reconcileCronjobs(versionId, existingCronjobs, desiredJobs, serverPrefix);

  await writeVariable(gameServerId, moduleId, CONFIG_HASH_KEY, currentConfigHash);
  await writeVariable(gameServerId, moduleId, LAST_PROCESSED_KEY, new Date().toISOString());
  await writeStatus(gameServerId, moduleId, {
    ok: true,
    errors: [],
    desiredCount: desiredJobs.length,
    configHash: currentConfigHash,
    ...result,
  });

  console.log(
    `dynamic-cronjobs: completed for server ${serverShortId}: ${result.created} created, ${result.updated} updated, ${result.removed} removed, ${desiredJobs.length} desired`,
  );
}

await main();
